const pins = $('Get Pins').all().map(i => i.json);
const boards = $('Get Boards').all().map(i => i.json);
function norm(s){ return (s==null?'':String(s)).replace(/[‐-―]/g,'-').replace(/\s+/g,' ').trim().toLowerCase(); }
function bName(r){ return r['Pinterest Board'] || r['Board Name'] || r['Board'] || ''; }
function bId(r){ return r['Tailwind Board ID'] || r['Board ID'] || ''; }
function resolveBoardId(pin){
  const direct = (pin['Board ID']==null?'':String(pin['Board ID'])).trim();
  if (direct) return direct;
  const name = norm(pin['Board']);
  if (!name) return '';
  let b = boards.find(r => norm(bName(r)) === name);
  if (!b) b = boards.find(r => { const bn = norm(bName(r)); return bn && (bn.includes(name) || name.includes(bn)); });
  return b ? String(bId(b)).trim() : '';
}
function toSendAt(v){
  if (v==null || v==='') return '';
  const s = String(v).trim();
  let dt = DateTime.fromISO(s);
  if(!dt.isValid) dt = DateTime.fromFormat(s,'yyyy-LL-dd HH:mm');
  if(!dt.isValid) dt = DateTime.fromFormat(s,'yyyy-LL-dd H:mm');
  if(!dt.isValid) dt = DateTime.fromFormat(s,'M/d/yyyy HH:mm:ss');
  if(!dt.isValid) dt = DateTime.fromFormat(s,'M/d/yyyy H:mm:ss');
  if(!dt.isValid) dt = DateTime.fromFormat(s,'M/d/yyyy H:mm');
  if(!dt.isValid){ const d=new Date(s); if(!isNaN(d.getTime())) dt=DateTime.fromJSDate(d); }
  if(!dt || !dt.isValid) return '';
  return dt.toUTC().toFormat("yyyy-LL-dd'T'HH:mm:ss'Z'");
}
function bigImg(u){ u=String(u||''); if(/cdn\.shopify\.com/i.test(u)){ return u.split('?')[0] + '?width=1000'; } return u; }
const nowPlus15 = $now.plus({ minutes: 15 });
const out = [];
for (const pin of pins) {
  if (norm(pin['Approval']) !== 'approved') continue;
  if (norm(pin['Status']) !== 'review') continue;
  const boardId = resolveBoardId(pin);
  const sendAt = toSendAt(pin['Scheduled Date']);
  const mediaUrl = bigImg(pin['Image 1 URL'] || '');
  let ready = true, reason = '';
  if (!mediaUrl) { ready=false; reason='No image URL'; }
  else if (!boardId) { ready=false; reason='Board not found: ' + (pin['Board']||'(blank)'); }
  else if (!sendAt) { ready=false; reason='Invalid scheduled date'; }
  else if (DateTime.fromISO(sendAt) <= nowPlus15) { ready=false; reason='Scheduled time must be 15+ min in the future'; }
  out.push({ json: {
    pinId: pin['Pin ID'], ready, reason,
    mediaUrl,
    title: String(pin['Pin Title']||'').slice(0,100),
    description: String(pin['Pin Description']||'').slice(0,500),
    url: pin['Blog Link'] || '',
    boardId, altText: String(pin['Alt Text']||'').slice(0,500),
    sendAt
  } });
}
return out;

const pin = $('Prepare').item.json;
const r = $json || {};
let status, err='', tw='';
if (r.error) { status='Error'; err = (typeof r.error === 'string') ? r.error : (r.error.message || JSON.stringify(r.error)); err = String(err).slice(0,300); }
else { status='Scheduled'; const o = Array.isArray(r)?(r[0]||{}):r; const postId = o.id || (o.data && (o.data.id || o.data.postId || (o.data.post && o.data.post.id))) || ''; tw = postId ? String(postId) : ''; }
return [{ json: { 'Pin ID': pin.pinId, 'Status': status, 'Tailwind Post ID': tw, 'Error': err } }];
